Here are comprehensive pytest-style unit tests for the `retry` function:

```python
import pytest
from unittest.mock import Mock, call
from your_module import retry  # Replace with actual module name


# ---------------------------------------------------------------------------
# Happy path tests
# ---------------------------------------------------------------------------

def test_succeeds_on_first_attempt():
    """Function succeeds immediately; called exactly once."""
    fn = Mock(return_value="ok")

    result = retry(fn)

    assert result == "ok"
    fn.assert_called_once()


def test_succeeds_on_second_attempt():
    """Function fails once, then succeeds."""
    fn = Mock(side_effect=[ValueError("fail"), "ok"])

    result = retry(fn)

    assert result == "ok"
    assert fn.call_count == 2


def test_succeeds_on_last_attempt():
    """Function fails on every attempt except the last (default max_attempts=3)."""
    fn = Mock(side_effect=[ValueError("fail"), ValueError("fail"), "ok"])

    result = retry(fn)

    assert result == "ok"
    assert fn.call_count == 3


def test_returns_none_when_fn_returns_none():
    """Explicit None return value is preserved."""
    fn = Mock(return_value=None)

    result = retry(fn)

    assert result is None


def test_returns_falsy_values_correctly():
    """Falsy return values (0, False, empty string) are preserved."""
    for falsy_value in [0, False, "", [], {}]:
        fn = Mock(return_value=falsy_value)
        result = retry(fn)
        assert result == falsy_value


def test_custom_max_attempts_success():
    """Succeeds within a custom max_attempts window."""
    fn = Mock(side_effect=[RuntimeError(), RuntimeError(), RuntimeError(), "ok"])

    result = retry(fn, max_attempts=4)

    assert result == "ok"
    assert fn.call_count == 4


# ---------------------------------------------------------------------------
# Edge case tests
# ---------------------------------------------------------------------------

def test_max_attempts_of_one_succeeds():
    """With max_attempts=1, a successful call works normally."""
    fn = Mock(return_value="ok")

    result = retry(fn, max_attempts=1)

    assert result == "ok"
    fn.assert_called_once()


def test_max_attempts_of_one_raises_immediately():
    """With max_attempts=1, a failing call raises without any retry."""
    fn = Mock(side_effect=ValueError("fail"))

    with pytest.raises(ValueError, match="fail"):
        retry(fn, max_attempts=1)

    fn.assert_called_once()


def test_large_max_attempts():
    """Works correctly with a large max_attempts value."""
    num_failures = 99
    fn = Mock(side_effect=[RuntimeError()] * num_failures + ["ok"])

    result = retry(fn, max_attempts=100)

    assert result == "ok"
    assert fn.call_count == 100


def test_fn_is_called_with_no_arguments():
    """retry always calls fn with no arguments."""
    fn = Mock(return_value=True)

    retry(fn)

    fn.assert_called_with()  # called with zero arguments


def test_different_exception_types_are_retried():
    """Different exception types across attempts are all retried."""
    fn = Mock(side_effect=[ValueError(), TypeError(), "ok"])

    result = retry(fn, max_attempts=3)

    assert result == "ok"
    assert fn.call_count == 3


